SELECT
    id, userId, title, content, category, tags, isPublic, createTime, updateTime
FROM notes
WHERE isDelete = 0

    AND userId = #{userId}


    AND (
        title LIKE CONCAT('%', #{keyword}, '%')
        OR content LIKE CONCAT('%', #{keyword}, '%')
        OR tags LIKE CONCAT('%', #{keyword}, '%')
    )


    AND category = #{category}


    AND tags LIKE CONCAT('%', #{tags}, '%')



        ORDER BY ${sortField}

            ${sortOrder}



        ORDER BY updateTime DESC

SELECT COALESCE(category, '未分类') as category, COUNT(*) as count FROM notes WHERE isDelete = 0
AND userId = #{userId}
GROUP BY category ORDER BY count DESC

SELECT DISTINCT TRIM(SUBSTRING_INDEX(SUBSTRING_INDEX(tags, ',', numbers.n), ',', -1)) as tag FROM notes CROSS JOIN ( SELECT 1 n UNION ALL SELECT 2 UNION ALL SELECT 3 UNION ALL SELECT 4 UNION ALL SELECT 5 ) numbers WHERE isDelete = 0
AND userId = #{userId}
AND tags IS NOT NULL AND tags != '' AND CHAR_LENGTH(tags) - CHAR_LENGTH(REPLACE(tags, ',', '')) >= numbers.n - 1 AND TRIM(SUBSTRING_INDEX(SUBSTRING_INDEX(tags, ',', numbers.n), ',', -1)) != '' ORDER BY tag
